module traffic_light
(
    input rst_n,
    input clk,
    input pass_request,
    output [7:0] clock,
    output red
);

    reg [7:0] cnt;
    reg [1:0] state;
    reg p_red, p_yellow, p_green;
    always @(*) begin
        case (state)
            2'b00: begin
                {p_red, p_yellow, p_green} = 3'b000;
                state = 2'b01;
            end
            2'b01: begin
                {p_red, p_yellow, p_green} = 3'b100;
                if (cnt == 60) begin
                    state = 2'b11;
                end
                else begin
                    state = 2'b01;
                end
            end
            2'b10: begin
                {p_red, p_yellow, p_green} = 3'b010;
                if (cnt == 5) begin
                    state = 2'b01;
                end
                else begin
                    state = 2'b10;
                end
            end
            2'b11: begin
                {p_red, p_yellow, p_green} = 3'b001;
                if (cnt == 10) begin
                    state = 2'b10;
                end
                else begin
                    state = 2'b11;
                end
            end
        endcase
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 8'd10;
        end
        else if (pass_request && green) begin
            cnt <= 8'd60;
        end
        else if (!green && p_green) begin
            cnt <= 8'd10;
        end
        else if (!yellow && p_yellow) begin
            cnt <= 8'd5;
        end
        else if (!red && p_red) begin
            cnt <= 8'd10;
        end
        else begin
            cnt <= cnt - 1;
        end
    end
    assign clock = cnt;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            {red, yellow, green} <= 3'b000;
        end
        else begin
            {red, yellow, green} <= {p_red, p_yellow, p_green};
        end
    end
endmodule
